            <nav class="catalog-pagination" aria-label="Pagination">
                <button class="btn btn-page"
                        disabled="@(currentPage <= 1)"
                        @onclick="() => GoToPage(currentPage - 1)">
                    Previous
                </button>

                @for (int i = 1; i <= totalPages; i++)
                {
                    var page = i;
                    <button class="btn btn-page @(page == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(page)">
                        @page
                    </button>
                }

                <button class="btn btn-page"
                        disabled="@(currentPage >= totalPages)"
                        @onclick="() => GoToPage(currentPage + 1)">
                    Next
                </button>
            </nav>
        }
    </section>
</div>

@code {
    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";

    private PagedResult<Product>? result;
    private int currentPage = 1;
    private const int PageSize = 12;
    private int totalPages;

    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        var categoryTask = LoadCategoriesAsync();
        var productTask = LoadProductsAsync();
        await Task.WhenAll(categoryTask, productTask);
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task LoadProductsAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
            totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            result = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        sortBy = "price_asc";
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await LoadProductsAsync();
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

